// Error trap — format an unhandled workflow failure into an owner DM.
// Error Trigger payload: { execution: {id, url, error, lastNodeExecuted, mode}, workflow: {id, name} }
const j = $input.first().json;
const ex = j.execution || {};
const wfMeta = j.workflow || {};
const err = ex.error || {};
const lines = [
  ':rotating_light: *Unhandled pipeline failure* (error trap)',
  '*Workflow:* ' + (wfMeta.name || wfMeta.id || '?'),
  '*Execution:* `' + (ex.id || '?') + '`' + (ex.url ? ' — ' + ex.url : ''),
  '*Last node:* `' + (ex.lastNodeExecuted || (err.node && err.node.name) || '?') + '`',
  '',
  '*Error:*',
  '\`\`\`',
  String(err.message || JSON.stringify(err).slice(0, 600) || 'no message').slice(0, 900),
  '\`\`\`',
  '',
  '_Check n8n executions; if a transcript call — the durable DLQ entry (the dlq/ folder in the vault repo) + plugin/scripts/redrive-dlq.js can recover the artifact._',
];
return [{ json: { dm_text: lines.join('\n') } }];
